def longest_special_path(nums, edges):
    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent):
        seen = set()
        max_length = 0
        min_nodes = float('inf')

        for child in graph[node]:
            if child != parent:
                length, nodes = dfs(child, node)
                if length > 0 and nums[child - 1] in seen:
                    continue
                seen.add(nums[child - 1])
                max_length = max(max_length, length + 1)
                min_nodes = min(min_nodes, nodes + 1)

        if len(seen) <= 2:
            return max_length, min_nodes
        else:
            return 0, float('inf')

    return dfs(0, -1)

