def longestUniquePath(nums, edges):
    n = len(nums)
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent, unique_count, max_unique):
        if len(set(unique_count.values())) == len(unique_count):
            max_unique = max(max_unique, sum(unique_count.values()))
        else:
            max_unique = max(max_unique, max(unique_count.values()) + 1)

        for child in graph[node]:
            if child != parent:
                unique_count[child] = unique_count.get(child, 0) + 1
                max_unique = max(max_unique, dfs(child, node, unique_count, max_unique))
                unique_count[child] -= 1

        return max_unique

    max_unique = 0
    for i in range(n):
        max_unique = max(max_unique, dfs(i, -1, {i: 1}, 0))

    return [max_unique, len(set(max_unique for _ in range(n)))]

