def minCost(nums, edges):
    n = len(nums)
    parent = list(range(n))

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        px, py = find(x), find(y)
        if px != py:
            parent[px] = py

    edges.sort(key=lambda x: nums[x[1]])

    cost = 0
    num_paths = 0
    for u, v in edges:
        if find(u) != find(v):
            cost += nums[v]
            union(u, v)
            num_paths += 1
            if num_paths == n - 1:
                break

    return [cost, n - 1]

