def soln(nums, edge):
    n = len(nums)
    graph = [[] for _ in range(n)]
    for u, v in edge:
        graph[u].append(v)

    def dfs(node, visited, path, max_path):
        visited.add(node)
        path.append(node)
        if len(path) > len(max_path):
            max_path[:] = path[:]
        for neighbor in graph[node]:
            if neighbor not in visited:
                dfs(neighbor, visited, path, max_path)
        path.pop()

    max_path = []
    min_node_count = float('inf')
    for i in range(n):
        visited = set()
        path = []
        dfs(i, visited, path, max_path)
        if len(path) > 1 and all(nums[path[j]] <= 2 * nums[path[j-1]] for j in range(1, len(path))):
            min_node_count = min(min_node_count, len(path))

    return [sum(nums[i] for i in max_path), min_node_count]

def longest_special_path(nums, edge):
