    graph = [[] for _ in range(n)]
    for u, v in edge:
        graph[u].append(v)

    def dfs(node):
        max_path = 0
        max_count = 0
        for neighbor in graph[node]:
            path, count = dfs(neighbor)
            if nums[path[-1]] < nums[node] * 2:
                if path + [node] > max_path:
                    max_path = path + [node]
                    max_count = count + 1
        return max_path, max_count

