def dfs(nums, edge, n):
    graph = {i: [] for i in range(n)}
    for u, v in edge:
        graph[u].append(v)
        graph[v].append(u)

    def dfs_helper(node, visited, path, min_cost):
        visited.add(node)
        path.append(node)
        min_cost = min(min_cost, nums[node])

        if len(path) >= 3 and path[0] == path[-1]:
            if min_cost * 2 > max(nums[path[i]] for i in range(len(path))):
                return len(path), min_cost

        for neighbor in graph[node]:
            if neighbor not in visited:
                result = dfs_helper(neighbor, visited, path, min_cost)
                if result is not None:
                    return result

        path.pop()
        return None

    max_length = 0
    min_cost = float('inf')
    for i in range(n):
        visited = set()
        result = dfs_helper(i, visited, [], nums[i])
