def diameterOfBinaryTree(nums, edge):
    n = len(nums)
    graph = [[] for _ in range(n)]

    for u, v in edge:
        graph[u].append(v)
        graph[v].append(u)

    def dfs(node, parent):
        max_diameter = 0
        for child in graph[node]:
            if child != parent:
                child_diameter = dfs(child, node)
                max_diameter = max(max_diameter, child_diameter)
        return max_diameter + nums[node]

    max_diameter = 0
    for i in range(n):
        if len(graph[i]) <= 2:
            curr_diameter = dfs(i, -1)
            max_diameter = max(max_diameter, curr_diameter)

    min_nodes = float('inf')
    for i in range(n):
        if len(graph[i]) <= 2:
            curr_diameter = dfs(i, -1)
            if curr_diameter == max_diameter:
                min_nodes = min(min_nodes, i + 1)

    return [max_diameter, min_nodes]

def pathWithMaxScore(nums, edges):
    n = len(nums)
    inf = float('inf')
    dp = [[inf] * n for _ in range(n)]
    dp[0][0] = nums[0]

    for i in range(1, n):
        for j in range(i):
            for u, v in edges:
                if u == j and v == i:
                    dp[i][j] = min(dp[i][j], dp[j][u] + nums[i])

    min_cost = inf
    max_length = 0
    for i in range(n):
        for j in range(i):
            if dp[i][j] <= 3 * nums[0]:
                min_cost = min(min_cost, dp[i][j])
                max_length = max(max_length, i - j)

    return [max_length, min_cost]
